mapper.select:
select count(1)
from function_info
where function_name = #{functionName}
  and class_name = #{className}
  and language = #{language}
  and code_text = #{codeText}
  and ifnull(input_desc, '') = ifnull(#{inputDesc}, '')
  and ifnull(output_desc, '') = ifnull(#{outputDesc}, '')
  and ifnull(remark, '') = ifnull(#{remark}, '')
  and ifnull(tester_case_count, 0) = ifnull(#{testerCaseCount}, 0)
